const API = "http://127.0.0.1:8000";

// =========================
// REQUEST HELPER
// =========================
const request = async (url, options = {}) => {
  const res = await fetch(url, options);
  const data = await res.json().catch(() => null);

  if (!res.ok) {
    throw new Error(data?.detail || "Request failed");
  }

  return data;
};

// =========================
// AUTH
// =========================
export const registerUser = (data) => {
  return request(`${API}/api/auth/register`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
};

export const loginUser = (data) => {
  return request(`${API}/api/auth/login`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
};

// =========================
// PATIENTS
// =========================
export const getPatients = () => {
  return request(`${API}/api/patients/`);
};

export const addPatient = (data) => {
  return request(`${API}/api/patients/`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
};

// =========================
// APPOINTMENTS
// =========================
export const getAppointments = () => {
  return request(`${API}/api/appointments/`);
};

export const addAppointment = (data) => {
  return request(`${API}/api/appointments/`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
};

// =========================
// PRESCRIPTIONS
// =========================
export const getPrescriptions = (patientId) => {
  return request(`${API}/api/prescriptions/${patientId}`);
};

export const addPrescription = (data) => {
  return request(`${API}/api/prescriptions/`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
};

// =========================
// SEARCH HELPERS
// =========================
export const searchPatientByPhone = (phone) => {
  return request(`${API}/api/patients/search/phone/${phone}`);
};

export const searchPatientById = (id) => {
  return request(`${API}/api/patients/search/id/${id}`);
};
